// export default Home;

import React from 'react';
import { Link } from 'react-router-dom';

const Home = () => {
  const capsules = [
    { id: 1, name: "Capsule 1", createdAt: "2023-10-01" },
    { id: 2, name: "Capsule 2", createdAt: "2023-10-02" },
  ];

  return (
    <div>
      <h1>Home Page</h1>
      <ul>
        {capsules.map((capsule) => (
          <li key={capsule.id}>
            <Link
              to={`/capsule/${capsule.id}`}
              state={{ capsuleName: capsule.name, createdAt: capsule.createdAt }}
            >
              {capsule.name}
            </Link>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Home;
